        System.Console.WriteLine($"Added medical record {record.RecordId} for patient {record.PatientId}.");
        return record.RecordId;
    }

    public MedicalRecord GetMedicalRecord(string recordId)
    {
        _medicalRecords.TryGetValue(recordId, out MedicalRecord record);
        if (record != null)
        {
            System.Console.WriteLine($"Retrieved medical record {record.RecordId} for patient {record.PatientId}.");
        }
        else
        {
            System.Console.WriteLine($"Medical record {recordId} not found.");
        }
        return record;
    }

    public Patient GetPatientDetails(string patientId)
    {
        _patients.TryGetValue(patientId, out Patient patient);
        if (patient != null)
        {
            System.Console.WriteLine($"Retrieved patient details for {patient.PatientId}.");
        }
        else
        {
            System.Console.WriteLine($"Patient {patientId} not found.");
        }
